"""Auto-generated by eval/iterate.py.

Hypothesis: The dominant failure mode is MISSING answers (model omits checks entirely, ~110+ instances). Explicitly mandating that every check ID must appear in the output with a non-empty answer should dramatically reduce MISSING rates and lift per-check accuracy.
Targets:    S14 :: UNVERIFIABLE → MISSING, S5 :: YES → MISSING, S7 :: YES → MISSING, S8 :: YES → MISSING, S13 :: YES → MISSING, S1 :: YES → MISSING, S3 :: YES → MISSING, S10 :: UNVERIFIABLE → MISSING, S2 :: YES → MISSING, S6 :: YES → MISSING
"""

from __future__ import annotations

NAME = 'v2_exhaustive_completion_mandate'

SYSTEM = 'You are an expert document forensics examiner. You analyze identity document images for signs of forgery by working through structured checklists.\n\nCRITICAL OUTPUT REQUIREMENT: You MUST return an answer for EVERY check ID listed in the hint page. Do NOT skip, omit, collapse, or summarize checks. If the checklist contains 65 checks, your JSON output MUST contain exactly 65 entries — one per check ID. Missing entries are treated as wrong answers and severely penalized. Before finalizing, count your entries and verify the count matches the checklist.\n\nAnswer each check with exactly one of:\n- YES — feature confirmed present as described\n- NO — feature absent, wrong, or anomalous (potential red flag)\n- WARN — borderline, degraded, or ambiguous; warrants closer inspection\n- UNVERIFIABLE — cannot determine from the image (resolution, glare, crop, missing side, precondition not applicable)\n- CONTEXT — generation-dependent or descriptive question; describe what you observe\n\nDecision rubric:\n- If the feature is plainly visible and matches the description → YES\n- If the feature is plainly visible and DOES NOT match → NO\n- If the feature is partially visible / degraded but you lean one way → WARN\n- If image quality, crop, side-missing, or the precondition does not apply → UNVERIFIABLE\n- NEVER leave a check out of the output. NEVER answer with an empty string.\n\nBe rigorous and independent. Do not assume the document is genuine.\n\nReturn ONLY valid JSON in the exact schema requested, with no markdown fences, no commentary, no preamble. Every check ID from the hint page MUST be a key in your response.'

GUIDANCE = ''


def build_user_text(*, page: dict, guidance: str | None, image_count: int) -> str:
    g = guidance if guidance is not None else GUIDANCE
    checklist = "\n\n".join(
        f"[{s['id']}] {s['title']}\n"
        + "\n".join(
            f"  {h[0]}: {h[1]}" + (f" [{h[2]}]" if h[2] else "")
            for h in s["hints"]
        )
        for s in page["sections"]
    )
    img_list = ", ".join(
        f"{i}={'front' if i == 0 else 'back' if i == 1 else f'image {i+1}'}"
        for i in range(image_count)
    )
    guidance_block = (
        f"\nEXPERT FORENSIC GUIDANCE (applies to whole document):\n{g}\n" if g else ""
    )
    return (
        f"Document type: {page['title']}\n"
        f"{guidance_block}\n"
        "Work through the following checklist against the attached document image(s). "
        "Provide a 1-sentence finding per check.\n\n"
        "For NO or WARN answers include \"bbox\" (normalized 0-1 [x1,y1,x2,y2]) and "
        f"\"imgIdx\" ({img_list}). Omit both otherwise.\n\n"
        f"CHECKLIST:\n{checklist}\n\n"
        "Return JSON in exactly this shape (no verdict/counts — computed downstream):\n"
        "{\"summary\":\"...\",\"sections\":[{\"id\":\"\",\"title\":\"\","
        "\"checks\":[{\"id\":\"\",\"answer\":\"YES|NO|WARN|UNVERIFIABLE|CONTEXT\","
        "\"finding\":\"1 sentence\",\"bbox\":[0,0,0,0],\"imgIdx\":0}]}]}"
    )
